// スプレッドシートから取得したデータをHTMLテーブルに変換（PDF横長複数ページ対応）
const items = $input.all();

if (items.length === 0) {
  return [{ json: { html: '<p>データがありません</p>' } }];
}

// ヘッダー（最初のアイテムのキーを使用）
const headers = Object.keys(items[0].json);

// HTMLテーブルを構築（横長PDF複数ページ用）
let html = `
<!DOCTYPE html>
<html lang="ja">
<head>
  <meta charset="UTF-8">
  <style>
    @page {
      size: A4 landscape;
      margin: 15mm;
    }

    * {
      box-sizing: border-box;
    }

    html, body {
      margin: 0;
      padding: 0;
      font-family: 'Segoe UI', 'Hiragino Kaku Gothic ProN', 'Meiryo', sans-serif;
      background-color: #ffffff;
      font-size: 10px;
    }

    .container {
      width: 100%;
      padding: 10px;
    }

    h1 {
      margin: 0 0 15px 0;
      font-size: 18px;
      color: #000;
      text-align: center;
    }

    table {
      width: 100%;
      border-collapse: collapse;
      background-color: white;
      font-size: 9px;
      table-layout: auto;
      border: 1px solid #000;
    }

    thead {
      display: table-header-group;
    }

    th {
      background-color: #f0f0f0;
      color: #000;
      padding: 8px 6px;
      text-align: left;
      font-weight: 600;
      font-size: 9px;
      vertical-align: middle;
      border: 1px solid #000;
      white-space: nowrap;
    }

    tbody tr {
      page-break-inside: avoid;
    }

    td {
      padding: 6px;
      color: #000;
      vertical-align: top;
      word-wrap: break-word;
      overflow-wrap: break-word;
      line-height: 1.3;
      border: 1px solid #000;
    }

    .footer {
      margin-top: 15px;
      text-align: right;
      font-size: 8px;
      color: #666;
    }
  </style>
</head>
<body>
  <div class="container">
    <table>
      <thead>
        <tr>
`;

// ヘッダー行を追加
for (const header of headers) {
  html += `          <th>${escapeHtml(header)}</th>\n`;
}

html += `        </tr>
      </thead>
      <tbody>
`;

// データ行を追加
items.forEach((item, index) => {
  html += `        <tr>\n`;
  for (const header of headers) {
    const value = item.json[header] ?? '';
    html += `          <td>${escapeHtml(String(value))}</td>\n`;
  }
  html += `        </tr>\n`;
});

html += `      </tbody>
    </table>
    <div class="footer">生成日時: ${new Date().toLocaleString('ja-JP')} / 全${items.length}件</div>
  </div>
</body>
</html>`;

// HTMLエスケープ関数
function escapeHtml(text) {
  const map = {
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  };
  return text.replace(/[&<>"']/g, m => map[m]);
}

// HTMLをバイナリデータとして出力
const binaryData = await this.helpers.prepareBinaryData(
  Buffer.from(html, 'utf-8'),
  'index.html',
  'text/html'
);

return [{ json: {}, binary: { file: binaryData } }];
